var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"조금만 더 내려가면, 과거를 오르는 범과 마주하게 되겠군.","JPN":"もう少し下りて行けば、過去を遡る虎と遭遇するだろう。","ENG":"Just a bit further down, and we’ll come face to face with the Tiger climbing up from the past.","TWN":"再往下走一點，我們就會遇到正在攀向過去的老虎。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"그러게요. 이렇게 깊이 거슬러 내려온 건 처음인데, 별 탈 없이 도착했어요.","JPN":"そうですね。こんなに深く時間を下ったのは初めてですが、無事辿り着きました。","ENG":"Right. I've never come this far down before, but we made it without any trouble.","TWN":"沒錯。這麼深入地逆流而上，還是第一次，幸好我們平安抵達。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"명달 대장이 삼군문의 머리에 서생 같은 똑똑한 길잡이를 둔 덕이겠죠.","JPN":"三軍門の参謀の座に、ショウのような賢い道案内役を配置したアカタツ隊長のおかげでしょう。","ENG":"Must be thanks to Commander Myeongdal having a clever guide like Seosaeng at the helm of Trivanguard.","TWN":"這都是因為有驍勇的明達，加上聰明的書生帶路，才能順利抵達。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"…연화야.","JPN":"……レンカ。","ENG":"…Yeonhwa.","TWN":"…蓮華。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"네?","JPN":"はい？","ENG":"Yes?","TWN":"怎麼了？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"아직 늦지 않았으니, 지금이라도 돌아가거라.","JPN":"まだ間に合う。今からでも帰れ。","ENG":"It's not too late. You can still turn back now.","TWN":"現在還來得及，你回去吧。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"이 아래엔 영광도 미래도 없다.","JPN":"この下には栄光も未来もない。","ENG":"There's no glory or future waiting down there.","TWN":"這裡沒有榮耀，也沒有未來。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"범은 연옥에 떨어지는 한이 있어도 모든 걸 게걸스럽게 삼킨 채 추락하고 다시금 깨어날 테니.","JPN":"虎は煉獄に堕ちようともすべてを貪りつくして墜落し、いずれ再び目を覚ます。","ENG":"Even if it means falling into purgatory, the Tiger will devour everything, fall, and rise again.","TWN":"老虎就算墜入煉獄，也會吞噬一切再次醒來。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"음…","JPN":"うーん……","ENG":"Hmm…","TWN":"嗯…"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L17_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"대장 마음은 알겠는데 별로 안 무섭네요.","JPN":"隊長の気持ちは分かりますけど、全然怖くありませんね。","ENG":"I get that you're worried, but I'm not scared.","TWN":"我知道隊長是好意，但我不害怕。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"절 겁주려면 도깨비 탈 정도는 쓰고 놀래키셨어야죠.","JPN":"私を怖気付かせたいなら、鬼の面を被って脅すぐらいはしないと。","ENG":"If you really wanted to scare me, you should've worn a demon mask or something.","TWN":"如果你想嚇我，至少得先扮成鬼吧。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"이제 막 재능을 꽃 피우기 시작한 네가 희생을 입에 담기엔 아직 이르단 것을 어찌 모르느냐?","JPN":"才能を開花させたばかりのお前が、犠牲を口にするのはまだ早すぎる。どうしてそれがわからないのだ。","ENG":"Don't you realize it's too early for someone just beginning to blossom to be talking about sacrifice?","TWN":"你才剛開始展露才華，怎麼能把犧牲掛在嘴上？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"아직 그 점괘를 마음에 담아두고 있는 거라면…","JPN":"あの占いをまだ気に留めているのなら……","ENG":"If you're still clinging to that old fortune…","TWN":"如果你還把那個算命的放在心上…"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"처음 저를 삼군문으로 데려올 때 말씀하셨잖아요. 범을 잡으려면 제가 필요하다고.","JPN":"私を三軍門に連れてきたときに仰ったでしょう。虎を倒すためには私が必要なのだと。","ENG":"You said it yourself when you brought me into Trivanguard. That I was needed to catch the Tiger.","TWN":"你第一次帶我來三軍門時不是說過，要抓住老虎，就需要我。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"이제 와서 저만 빼놓고 혼자 갈 생각일랑 마셔요.","JPN":"今更私を帰して一人で行くなんてなしです。","ENG":"So don't even think about leaving me behind now.","TWN":"現在想把我丟下，自己一個人去，門都沒有。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"서생이 곧 기슭으로 내려가는 동앗줄을 내려줄 게다. 잠시 숨 돌릴 틈은 있겠지.","JPN":"もうすぐショウが麓へ降りるための縄を下ろしてくれるだろう。一息つく暇はあるはずだ。","ENG":"Seosaeng will soon lower the rope down to the next ridge. You should have a moment to catch your breath.","TWN":"書生很快就會放下通往山麓的繩索。我們會有喘息的時間。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"아.","JPN":"あ。","ENG":"Ah.","TWN":"喔。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"그러고보니 좀 전에 봐 둔 개울이 있는데, 세수나 좀 하고 올게요.","JPN":"そういえば、さっき小川を見つけたので、顔でも洗ってきます。","ENG":"Come to think of it, I saw a stream earlier. I'm going to go wash my face.","TWN":"我剛才看到一條小溪，我先去洗個臉。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"몰래 엿보진 않으실 거죠-?","JPN":"覗き見なんてしないですよね？","ENG":"You're not going to peek, right?","TWN":"你不會偷看吧？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"세수라더니?","JPN":"顔を洗うだけじゃないのか？","ENG":"Wash your face, you said?","TWN":"不是洗臉嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"아하하, 물이 좋으면 맘이 바뀔지도 모르잖아요.","JPN":"あはは、水がきれいすぎて気が変わるかもしれませんから。","ENG":"Haha, if the water feels nice, I might just change my mind.","TWN":"哈哈，要是水乾淨的話，我可能會改變心意。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"휴우…","JPN":"ふう……","ENG":"Whew…","TWN":"呼…"},"stage":{"bg":"REEDS_FIELD_02","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"물은 찾았지만, 생각보다 멀리 와버렸네.","JPN":"水は見つかったものの、思ったより遠くまで来てしまったわ。","ENG":"I found the water, but I've wandered farther than I expected.","TWN":"找到水了，但沒想到有點遠。"},"stage":{"bg":"REEDS_FIELD_02","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"적당히 시원하고 좋구나… 역시 세수만 하는 건 아깝지?","JPN":"涼しくて気持ちいい……やっぱり顔を洗うだけじゃもったいないわね。","ENG":"It's nice and cool… feels like a waste to only wash my face.","TWN":"水真涼快，好舒服…只洗臉有點可惜呢？"},"stage":{"bg":"REEDS_FIELD_02","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"응…?","JPN":"ん……？","ENG":"Huh…?","TWN":"嗯…？"},"stage":{"bg":"REEDS_FIELD_02","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};